from sympy import tribonacci
def A004781(n):
    def f(x):
        s = bin(x)[-1:1:-1]
        return n-1+sum(tribonacci(i+2) for i in range(len(s)) if s[i]=='1' and not '111' in s[i+1:])+('111' not in s)
    m, k = n, f(n)
    while m != k: m, k = k, f(k)
    return m # _Chai Wah Wu_, Jun 09 2026

